CustomField.formula:
IF(
AND (
CONTAINS($Label.SMARTIDFRecordTypeIds,RecordType.DeveloperName),
ISPICKVAL(Origin,"SMART"),
/*NOT(ISBLANK( TEXT(External_Case_Category__c))),*/
/*NOT(ISBLANK( TEXT(External_Case_Detail__c))),*/
/*NOT(ISBLANK(Subsidiary_Indicator_Stored__c)),*/
NOT(ISBLANK(Subsidiary_Indicator__c)),
NOT(ISBLANK( TEXT(Origin))),
/*NOT(ISBLANK(TEXT(Service_Provider__c))),*/
NOT(ISBLANK(TEXT(Sales_Channel__c))),
NOT(ISBLANK(TEXT(Status))),
/*NOT(ISBLANK(Last_description__c)),*/
/*NOT(ISBLANK(Partner_CaseId__c)),*/
NOT(ISBLANK(Order_Id__c)),
AND (
OR(ISPICKVAL(Status,"Pending - External"),ISPICKVAL(Status,"Closed")))),True,False)
